const items=$input.all(); const r=Array.isArray(items[0]?.json)?items[0].json[0]:items[0]?.json; const p=Array.isArray(items[1]?.json)?items[1].json[0]:items[1]?.json;
if(!r&&!p) return [{json:{skip:true}}]; const tk=r?.symbol||p?.symbol||'?';
return [{json:{ticker:tk,period_date:r?.date||new Date().toISOString().split('T')[0],revenue:p?.revenue||null,net_income:p?.netIncome||null,eps:p?.eps||null,pe_ratio:r?.priceEarningsRatio||p?.peRatio||null,pb_ratio:r?.priceToBookRatio||null,ps_ratio:r?.priceToSalesRatio||null,debt_to_equity:r?.debtEquityRatio||null,roe:r?.returnOnEquity||null,roa:r?.returnOnAssets||null,current_ratio:r?.currentRatio||null,dividend_yield:r?.dividendYield||null,payout_ratio:r?.payoutRatio||null,revenue_growth:r?.revenueGrowth||null,earnings_growth:r?.netIncomeGrowth||null,free_cash_flow:p?.freeCashFlow||null,gross_margin:r?.grossProfitMargin||null,operating_margin:r?.operatingProfitMargin||null,net_margin:r?.netProfitMargin||null,market_cap:p?.mktCap||null}}];
